const body = $input.item.json.body;
const userId = body.user_id;
const samples = Array.isArray(body.sample_texts) ? body.sample_texts : [body.sample_texts];

if (!userId || userId.trim().length === 0) {
  throw new Error('user_id is required and cannot be empty.');
}

if (!samples || samples.length < 3) {
  throw new Error('Minimum 3 sample texts required. Received: ' + (samples ? samples.length : 0));
}

const validated = samples
  .filter(s => typeof s === 'string' && s.trim().length > 20)
  .map(s => s.trim());

if (validated.length < 3) {
  throw new Error('Minimum 3 non-empty sample texts (>20 chars each) required. Valid received: ' + validated.length);
}

const concatenated = validated
  .map((text, i) => `--- SAMPLE ${i + 1} (${text.length} chars) ---\n${text}`)
  .join('\n\n');

return [
  {
    json: {
      user_id: userId,
      concatenated_samples: concatenated,
      sample_count: validated.length,
      total_chars: concatenated.length
    }
  }
];

const raw = $input.item.json;
const userId = $('Validate and Concatenate Samples').item.json.user_id;

let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(raw).substring(0, 200));
}

const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw snippet: ' + cleaned.substring(0, 400));
}

const required = ['tone', 'vocabulary', 'rhythm', 'taboo', 'signatures', 'pov', 'summary'];
for (const key of required) {
  if (!(key in parsed)) {
    throw new Error('Missing required key in Claude response: ' + key);
  }
}

if (!Array.isArray(parsed.tone)) parsed.tone = [];
if (!Array.isArray(parsed.taboo)) parsed.taboo = [];
if (!Array.isArray(parsed.signatures)) parsed.signatures = [];

if (!parsed.vocabulary || typeof parsed.vocabulary !== 'object') parsed.vocabulary = {};
if (!Array.isArray(parsed.vocabulary.jargon)) parsed.vocabulary.jargon = [];
if (!Array.isArray(parsed.vocabulary.preferred_verbs)) parsed.vocabulary.preferred_verbs = [];
if (!Array.isArray(parsed.vocabulary.power_words)) parsed.vocabulary.power_words = [];

if (!parsed.rhythm || typeof parsed.rhythm !== 'object') parsed.rhythm = {};
if (!Array.isArray(parsed.rhythm.notable_patterns)) parsed.rhythm.notable_patterns = [];

if (typeof parsed.rhythm.use_of_fragments === 'string') {
  parsed.rhythm.use_of_fragments = parsed.rhythm.use_of_fragments.toLowerCase() === 'true';
}

if (!parsed.pov || typeof parsed.pov !== 'object') parsed.pov = { dominant: 'unknown', usage_notes: '' };
if (typeof parsed.summary !== 'string') parsed.summary = '';

return {
  json: {
    user_id: userId,
    brand_voice: parsed
  }
};

